      (Array.isArray(cloneValue) && !cloneValue.length) ||
      isEmptyObject(cloneValue);

    if (!field || field._f || isNullOrUndefined(cloneValue) || isEmpty) {
      setFieldValue(name, cloneValue, options, skipClone, skipStateEmit);
